quem visita. Um bairro com personalidade própria — assim como você.</span></span></p>
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('1504c383-1647-4c06-984f-bf7b484e8658', 'led-mada', 'LED Madá', 'Vila para quem quer o sossego Madá para quem prefere o agito da Vila Madalena.', NULL, 'em_construcao', NULL, '<p>O LED Vila Madalena é um empreendimento que traduz o estilo vibrante e artístico do bairro em um projeto contemporâneo e sofisticado. Com arquitetura assinada por <strong data-start="499" data-end="516">LE Arquitetos</strong>, paisagismo de <strong data-start="532" data-end="542">Cardim</strong> e interiores do escritório <strong data-start="570" data-end="590">Suíte Arquitetos</strong>, o projeto une design, conforto e bem-estar em um dos pontos mais altos e desejados de São Paulo.</p>
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('8f99cc46-4870-406f-831f-ee8f7656800f', '1800-oscar-pinheiros', '1800 Oscar Pinheiros', 'Proposta contemporânea que eleva o morar e redefine a forma de viver em São Paulo', NULL, 'em_construcao', NULL, '<p data-start="224" data-end="595">Entre as ruas arborizadas de Pinheiros e a energia sofisticada do Jardins, o <strong data-start="301" data-end="325">1800 Oscar Pinheiros</strong> ocupa um dos endereços mais desejados da cidade. Um ponto raro, onde vitrines que ditam tendências, restaurantes de chefs reconhecidos internacionalmente e uma atmosfera vibrante convivem com a tranquilidade do bosque da USP.</p>
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('8d864670-3761-4b6b-901c-ba126faba762', 'arborea-itaim', 'Arbórea Itaim', 'Arbórea Itaim está localizado em um dos pontos mais conceituados de São Paulo', NULL, 'pronto_para_morar', NULL, '<p>Viver no Itaim é escolher o melhor para sua família, somando mais beleza, segurança e tranquilidade à arte de morar bem.</p>
