INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('30cbef5d-95e1-4477-9970-102e622d5bc1', 'led-vila', 'LED Vila', 'Vila para quem quer o sossego. Madá para quem prefere o agito da Vila Madalena.', NULL, 'em_construcao', NULL, 'O LED Vila Madalena é um empreendimento que traduz o estilo vibrante e artístico do bairro em um projeto contemporâneo e sofisticado.
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('94f0226c-fa61-4340-8226-a6fcb790963b', 'autorjardins', 'Autór Jardins', 'Quando se olha à distância, a fachada com vistas em 360 graus não é óbvia: é uma arquitetura que marca uma nova dinâmica na cidade.', NULL, 'lancamento', NULL, 'Autoral e contemporânea, a arquitetura revela volumes bem resolvidos, proporções elegantes e uma composição que valoriza a luz, os materiais e o entorno. Presença marcante, sem renunciar à atemporalidade. O design é protagonista. Cada linha, cada elemento construtivo carrega uma intenção precisa.<p></p>
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('19f83ad1-2ff2-4a3b-b5de-9468145cc14f', 'raro-perdizes', 'Raro Perdizes', 'Perdizes é o endereço da vida que você sempre quis.', NULL, 'pronto_para_morar', NULL, '<p><span class="TextRun SCXW173972055 BCX0" lang="PT-BR" xml:lang="PT-BR" data-contrast="auto"><span class="NormalTextRun SCXW173972055 BCX0">Morar no </span></span><span class="TextRun SCXW173972055 BCX0" lang="PT-BR" xml:lang="PT-BR" data-contrast="auto"><span class="NormalTextRun SCXW173972055 BCX0">Raro Perdizes</span></span><span class="TextRun SCXW173972055 BCX0" lang="PT-BR" xml:lang="PT-BR" data-contrast="auto"><span class="NormalTextRun SCXW173972055 BCX0"> é ter tudo isso ao seu redor. É esquecer o carro na garagem e viver a cidade a pé. É ter um parque linear como vizinho para caminhar, correr ou pedalar com seu cachorro.</span></span><span class="EOP SCXW173972055 BCX0" data-ccp-props="{"134233117":false,"134233118":false,"335559738":240,"335559739":240}"> </span></p>
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('80d0bcf2-ccbe-4fdd-9897-2e178b6d1358', 'brkln-90-stay', 'Brooklin Noventa Stay', 'Um projeto extraordinário por dentro e por fora.', NULL, 'em_construcao', NULL, 'Da porta para dentro, toda a modernidade e conforto que a sua vida pede. Projeto atual, design inovador e paisagismo contemporâneo, criados por profissionais renomados. Da porta para fora, o Brooklin, um dos bairros mais desejados da cidade, com toda a comodidade, mobilidade e praticidade que o seu ritmo exige. <p></p> Cada metro quadrado é pensado para seu conforto.
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('d2b44921-d34b-408e-bb38-426f02128b2d', 'lapa', 'Viva Benx - Lapa', 'Viver bem, com acesso, qualidade e localização privilegiada.', 'his_e_hmp', 'entregue', NULL, 'O Viva Benx Lapa traz um novo jeito de viver a cidade, unindo localização privilegiada, mobilidade e infraestrutura completa. Com lazer equipado, soluções sustentáveis e apartamentos funcionais, o projeto oferece qualidade de vida a preços acessíveis, valorizando o bem-estar, a praticidade do dia a dia e a conexão com o melhor da zona oeste.', 'Rúbio & Luongo Arquitetura', 'Roberto Riscala', 'Jairo de Sender', 352, 9, NULL, 2, 4323.17, NULL, '34 m2 e 37 m2', NULL, '2 dorms.', '93', 'Empreendimento: Viva Benx Chácara Sto. Antônio. Incorporadora: MAR NAPOLES DESENVOLVIMENTO IMOBILIARIO SPE LTDA. Memorial de Incorporação registrado sob o R.19 na Matrícula 180.403 do 11º Cartório de Imóveis de São Paulo/SP, em 29/10/2020. Os acabamentos, o mobiliário, os eletrodomésticos e os demais itens do apartamento decorado e das perspectivas não fazem parte do Memorial Descritivo. A vegetação que compõe o paisagismo retratado nas perspectivas é meramente ilustrativa e apresenta porte adulto de referência. Na entrega do empreendimento, essa vegetação poderá apresentar diferenças de tamanho e porte, mas estará de acordo com o Projeto Paisagístico e em conformidade com as aprovações ambientais. A vista apresentada nas imagens é meramente elucidativa, não sendo a fotografia exata do local. Material preliminar, sujeito à alteração. Intermediação: Bem Imobiliária - Av. Dr. Cardoso de Melo, 1.470, Vila Olímpia, São Paulo/SP - Tel.: (11) 3847-1333 - Creci: 20.197-J. Os empreendimentos Viva Benx Casa do Ator, Viva Benx Chácara Santo Antônio, Viva Benx Pinheiros, Viva Benx Faria Lima, Viva Benx Vila Olímpia, Viva Benx Santana, Viva Benx Tatuapé, Viva Benx Mooca, Viva Benx Vila Mariana, Viva Benx Jardim Marajoara II, Viva Benx Jardim Marajoara I, Viva Benx Vila Mascote, Viva Benx Nações Unidas II, Viva Benx Nações Unidas I, Viva Benx Cambuci II, Viva Benx Cambuci I, Viva Benx Vila Leopoldina II, Viva Benx Vila Leopoldina e Viva Benx Lapa possuem unidades enquadradas como HMP (Habitação de Mercado Popular), destinadas às pessoas com renda familiar mensal de até 10 (dez) salários-mínimos, e terão preço de venda de até R$ 537.672,71 e/ou HIS-2 (Habitação de Interesse Social), destinadas às pessoas com renda familiar mensal de até 06 (seis) salários-mínimos, e terão preço de venda de até R$ 383.636,74. Os preços de venda serão corrigidos anualmente pelo Índice Nacional de Custo da Construção – INCC, a partir de janeiro de 2026.', 'Av. José Maria de Faria, 294', 'Av. José Maria de Faria, 294', '05038-190', NULL, NULL, 'https://m.uber.com/go/pickup?drop%5B0%5D=%7B%22addressLine1%22%3A%22Viva%20Benx%20Lapa%22%2C%22addressLine2%22%3A%22Av.%20Jos%C3%A9%20Maria%20de%20Faria%2C%20294%20-%20Lapa%20-%20S%C3%A3o%20Paulo%20-%20SP%2C%2005038-190%22%2C%22id%22%3A%2250e08ec8-35e1-44ad-9004-18a06587201f%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.511923%2C%22longitude%22%3A-46.7005387%2C%22provider%22%3A%22uber_places%22%7D&amp;marketing_vistor_id=904298d5-f2e2-4b76-9498-fdd3b39d18d9&amp;uclick_id=234a1efd-c2e9-4f29-a9ae-b3dcb880a591', 'https://www.google.com/maps/search/?api=1&amp;query=Av.+Jos%C3%A9+Maria+de+Faria,+294+S%C3%A3o+Paulo', 'https://www.waze.com/pt-BR/live-map/directions/br/sp/viva-benx-lapa?to=place.ChIJhTBDcEv3zpQRCy44yoYN8E8', 'wp/2026/04/VivaBenx-Lapa-Praca-3.webp', 'wp/2026/04/vivabenx-lapa.png', 'https://www.youtube.com/watch?v=Rr5GgwsVDvQ', 'wp/2026/04/Thumb-VB-Lapa-1.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, false, true, true, false, '["Portaria Blindada", "Lobby com Pé-Direito Duplo", "Lazer Completo Equipado e Decorado", "Lavanderia Coletiva Profissional", "Wi-fi nas Áreas Comuns", "Iluminação Inteligente nas Áreas Comuns"]', '[{"nome": "Lobby"}, {"nome": "Salão de Festas"}, {"nome": "Espaço gourmet"}, {"nome": "Brinquedoteca"}, {"nome": "Playground"}, {"nome": "Fitness"}, {"nome": "Pet Place"}, {"nome": "Coworking"}, {"nome": "Home cinema"}, {"nome": "Bicicletário"}, {"nome": "Espaço Delivery"}, {"nome": "Lavanderia"}, {"nome": "Horta comunitária"}, {"nome": "Praça do Fogo"}, {"nome": "Churrasqueira com forno de pizza"}, {"nome": "Piscina com Deck Molhado"}, {"nome": "Área comum 1", "imagem": "wp/2026/04/VivaBenx-Lapa-Praca-2-scaled.webp"}, {"nome": "Área comum 2", "imagem": "wp/2026/04/VivaBenx-Lapa-Fitness-3.webp"}, {"nome": "Área comum 3", "imagem": "wp/2026/04/VivaBenx-Lapa-Fitness-2.webp"}, {"nome": "Área comum 4", "imagem": "wp/2026/04/VivaBenx-Lapa-Fitness.webp"}, {"nome": "Área comum 5", "imagem": "wp/2026/04/VivaBenx-Lapa-Piscina.webp"}, {"nome": "Área comum 6", "imagem": "wp/2026/04/VivaBenx-Lapa-Piscina-2.webp"}, {"nome": "Área comum 7", "imagem": "wp/2026/04/VivaBenx-Lapa-Playground.webp"}, {"nome": "Área comum 8", "imagem": "wp/2026/04/VivaBenx-Lapa-Playground-2.webp"}, {"nome": "Área comum 9", "imagem": "wp/2026/04/VivaBenx-Lapa-Churrasqueira.webp"}, {"nome": "Área comum 10", "imagem": "wp/2026/04/VivaBenx-Lapa-Lavanderia-2.webp"}, {"nome": "Área comum 11", "imagem": "wp/2026/04/VivaBenx-Lapa-Lavanderia.webp"}, {"nome": "Área comum 12", "imagem": "wp/2026/04/VivaBenx-Lapa-Lavanderia-3.webp"}]', '[]', '[{"titulo": "Metrô Palmeiras / Barra Funda - 13 min de carro", "distancia": ""}, {"titulo": "Mercado Municipal da Lapa - 4 min de carro", "distancia": ""}, {"titulo": "Shopping Center Lapa - 5 min de carro", "distancia": ""}, {"titulo": "Extra Hipermercado - 7 min de carro", "distancia": ""}, {"titulo": "Faculdades Integradas Rio Branco - 1 min a pé", "distancia": ""}]', '[]', '629fce57-d783-4d19-9216-cbb93ca47d26', 'c50a75e5-4e20-4f41-9c6e-2491b9bd9ab6', '52a9fa5a-17de-42bd-80e8-3981715ec6e7', 'e8c32e6a-393c-4ad2-8bcc-8c954844bd9c', '2026-06-04 01:31:26.10291', '2026-06-04 02:20:59.69', NULL, NULL, '["viva-benx-vila-leopoldina-iii", "viva-benx-estacao-vila-mariana"]', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('96252c51-5e49-427d-ac5a-d0b334639090', 'j329-itaim', 'J329 Itaim', 'Morar no Itaim é viver onde tudo acontece.', NULL, 'lancamento', NULL, '<p>O J329 Itaim foi pensado para quem valoriza localização, praticidade e um estilo de vida dinâmico. Apartamentos que unem design, conforto e a metragem ideal para quem busca viver com qualidade no centro de um dos bairros mais desejados de São Paulo.</p>
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('0ae8dfa9-5509-44bc-b5b5-f613a930d2ee', '280-art-boulevard', '280 Art Boulevard', 'Arte, arquitetura e exclusividade em um dos endereços mais desejados de São Paulo.', NULL, 'lancamento', NULL, '<p>O 280 Art Boulevard é mais do que um empreendimento: é uma obra que conecta arquitetura autoral e design contemporâneo, com uma curadoria de espaços pensada para proporcionar experiências únicas. Com plantas amplas, acabamentos de altíssimo padrão e lazer digno dos melhores endereços internacionais, traduz exclusividade e sofisticação no coração do Itaim Bibi.</p>
