INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('b927267f-3c3f-4059-b45c-e7cb3807f3ca', 'place-klabin-residence-2', 'Place Klabin Résidence', 'A qualidade e o alto padrão Hines e Benx chegam ao melhor do Klabin.', NULL, 'pronto_para_morar', NULL, '<p><span class="TextRun SCXW26578466 BCX0" lang="PT-BR" xml:lang="PT-BR" data-contrast="auto"><span class="NormalTextRun SCXW26578466 BCX0">Viver na Chácara Klabin é escolher a tranquilidade de um bairro predominantemente residencial, com ruas calmas e arborizadas.</span></span><span class="LineBreakBlob BlobObject DragDrop SCXW26578466 BCX0"><span class="SCXW26578466 BCX0"> </span><br class="SCXW26578466 BCX0" /></span><span class="TextRun SCXW26578466 BCX0" lang="PT-BR" xml:lang="PT-BR" data-contrast="auto"><span class="NormalTextRun SCXW26578466 BCX0"> É optar por um ar de interior em meio ao dinamismo da cidade. Um clima acolhedor que convida a um passeio leve ou à contemplação do pôr do sol. Uma área nobre que orgulha seus moradores </span></span><span class="TextRun SCXW26578466 BCX0" lang="PT-BR" xml:lang="PT-BR" data-contrast="auto"><span class="NormalTextRun SCXW26578466 BCX0">e encanta quem visita. Um bairro com personalidade própria — assim como você.</span></span></p>
