INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('576d7057-aed5-4ad3-a038-8a8b88d858ed', 'estilo-pompeia', 'Viva Benx - Estilo Pompéia', 'O sucesso do Viva Benx chega ao tradicional bairro da Pompeia.', 'his', 'pronto_para_morar', NULL, 'Localizado em um dos bairros mais tradicionais de São Paulo, o Viva Benx Estilo Pompeia reúne praticidade, mobilidade e qualidade de vida. O projeto combina arquitetura contemporânea, lazer completo e soluções sustentáveis, com áreas comuns pensadas para o bem-estar e convivência. Com infraestrutura completa no entorno e fácil acesso a transporte, comércio e serviços, oferece uma experiência urbana integrada, moderna e acessível.', 'MCAA Arquitetos', 'Roberto Riscala', 'Maria Clara Marback e Larissa Perna', 304, 26, 16, 1, 1653, NULL, '24m² a 45m²', NULL, '1 e 2 dorms.', NULL, 'Empreendimento: Viva Benx Pompéia. Incorporadora: M.A.R. LION DESENVOLVIMENTO IMOBILIARIO SPE LTDA. Memorial de Incorporação registrado sob o R.3. da matrícula n° 136.439 do 2° Oficial de Registro de Imóveis de São Paulo/SP, em 10/05/2021. Os acabamentos, o mobiliário, os eletrodomésticos e os demais itens do apartamento decorado e das perspectivas não fazem parte do Memorial Descritivo. A vegetação que compõe o paisagismo retratado nas perspectivas é meramente ilustrativa e apresenta porte adulto de referência. Na entrega do empreendimento, essa vegetação poderá apresentar diferenças de tamanho e porte, mas estará de acordo com o Projeto Paisagístico e em conformidade com as aprovações ambientais. A vista apresentada nas imagens é meramente elucidativa, não sendo a fotografia exata do local. Material preliminar, sujeito à alteração. Intermediação: Bem Imobiliária - Av. Dr. Cardoso de Melo, 1.470, Vila Olímpia, São Paulo/SP - Tel.: (11) 3847-1333 - Creci: 20.197-J. Abyara Brokers- Av. Ibirapuera, 2332, 5º Andar, Bloco 1, Edifício Torre Ibirapuera I, Indianópolis, São Paulo/SP - Tel.: (11) 3888-9201 – Creci: 42766-J. Todas as unidades do empreendimento, com exceção às de finais 15 e 16, do 6° ao 24º pavimento são unidades HIS-2 (Habitação de Interesse Social), destinadas às pessoas com renda familiar mensal de até 06 (seis) salários-mínimos, e terão preço de venda de até R$ 383.636,74. Os preços de venda serão corrigidos anualmente pelo Índice Nacional de Custo da Construção – INCC, a partir de janeiro de 2026.', 'Av. Pompéia, 713', 'Av. Pompéia, 713 - Pompéia - São Paulo/SP', '05023-000', NULL, NULL, 'https://m.uber.com/go/pickup?drop%5B0%5D=%7B%22addressLine1%22%3A%22Viva%20Benx%20Pompeia%22%2C%22addressLine2%22%3A%22Av.%20Pomp%C3%A9ia%2C%20713%20-%20Pompeia%2C%20S%C3%A3o%20Paulo%20-%20SP%22%2C%22id%22%3A%22ChIJscJXOUpXzpQR_fzIgguv3Xc%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.530915099999998%2C%22longitude%22%3A-46.685251799999996%2C%22provider%22%3A%22google_places%22%7D&amp;marketing_vistor_id=904298d5-f2e2-4b76-9498-fdd3b39d18d9&amp;uclick_id=1235e595-2e34-4ae3-9f67-b17a615b07f1', 'https://www.google.com/maps/search/?api=1&amp;query=Av.+Pomp%C3%A9ia,+713+-+Pomp%C3%A9ia+-+S%C3%A3o+Paulo+SP', 'https://www.waze.com/pt-BR/live-map/d