INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('a109a51a-9e67-4025-b054-5fd0a1317ea0', 'vila-olimpia', 'Viva Benx - Vila Olímpia', 'Viver bem, com mobilidade, lazer e localização privilegiada.', 'his_e_hmp', 'pronto_para_morar', NULL, 'O Viva Benx Vila Olímpia oferece um novo jeito de viver a cidade, com localização estratégica e alta mobilidade. Com lazer completo, rooftop e soluções inteligentes, o projeto une praticidade, conforto e eficiência. Ideal para morar ou investir, proporciona qualidade de vida com acesso facilitado a serviços, trabalho e entretenimento.', 'Octávio de Siqueira', 'Roberto Riscala', 'Maria Clara Marback e Larissa Perna', 458, 25, NULL, 1, 2900, NULL, '24m², 31m² e 42m²', NULL, '1 e 2 Dorms', 'Sem Vagas', 'Incorporação Imobiliária do Viva Benx Vila Olímpia registrada sob o R.05 da Matrícula 182.596 do 4º Oficial de Registro de Imóveis de São Paulo em 23/10/2020. Os acabamentos, o mobiliário, os eletrodomésticos e os demais itens do apartamento decorado e das perspectivas não fazem parte do Memorial Descritivo. A vegetação que compõe o paisagismo retratado nas perspectivas é meramente ilustrativa e apresenta porte adulto de referência. Na entrega do empreendimento, essa vegetação poderá apresentar diferenças de tamanho e porte, mas estará de acordo com o Projeto Paisagístico e em conformidade com as aprovações ambientais. A vista apresentada nas imagens é meramente elucidativa, não sendo a fotografia exata do local. Material preliminar, sujeito à alteração. Intermediação: Bem Imobiliária - Av. Dr. Cardoso de Melo, 1.470, Vila Olímpia, São Paulo/SP - Tel.: (11) 3847-1333 - Creci: 20.197-J. Os empreendimentos Viva Benx Casa do Ator, Viva Benx Chácara Santo Antônio, Viva Benx Pinheiros, Viva Benx Faria Lima, Viva Benx Vila Olímpia, Viva Benx Santana, Viva Benx Tatuapé, Viva Benx Mooca, Viva Benx Vila Mariana, Viva Benx Jardim Marajoara II, Viva Benx Jardim Marajoara I, Viva Benx Vila Mascote, Viva Benx Nações Unidas II, Viva Benx Nações Unidas I, Viva Benx Cambuci II, Viva Benx Cambuci I, Viva Benx Vila Leopoldina II, Viva Benx Vila Leopoldina e Viva Benx Lapa possuem unidades enquadradas como HMP (Habitação de Mercado Popular), destinadas às pessoas com renda familiar mensal de até 10 (dez) salários-mínimos, e terão preço de venda de até R$ 537.672,71 e/ou HIS-2 (Habitação de Interesse Social), destinadas às pessoas com renda familiar mensal de até 06 (seis) salários-mínimos, e terão preço de venda de até R$ 383.636,74. Os preços de venda serão corrigidos anualmente pelo Índice Nacional de Custo da Construção – INCC, a partir de janeiro de 2026.', 'Alameda Raja Gabaglia, 289', 'Alameda Raja Gabaglia, 289', '04551-090', NULL, NULL, 'https://m.uber.com/go/pickup?drop%5B0%5D=%7B%22addressLine1%22%3A%22Viva%20Benx%20Vila%20Ol%C3%ADmpia%22%2C%22addressLine2%22%3A%22Al.%20Raja%20Gabaglia%2C%20271%20-%20Itaim%20Bibi%20-%20S%C3%A3o%20Paulo%20-%20SP%2C%2004551-090%22%2C%22id%22%3A%22a3b6e94a-3c84-40fb-9391-d4ed55ebba85%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.5967367%2C%22longitude%22%3A-46.689814%2C%22provider%22%3A%22ube