INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('664e2e97-cf89-4074-94bb-8530d3072637', '6844-2', 'Parque Global - Torre Ibirapuera', 'O que você nunca ousou sonhar, nós ousamos realizar.', NULL, 'em_construcao', NULL, 'Um bairro interligado com a cidade - Verde, seguro, confortável e exclusivo. Um verdadeiro paraíso bem no meio de uma das maiores cidades do mundo.', 'MCAA', 'Enea | Cardim Arquitetura Paisagística', 'Carlos Rossi | UNITED | Archea | Superlimão', 81, 47, NULL, 1, 44397.06, NULL, NULL, NULL, NULL, '4 e 5 vagas por apartamento', 'Em conformidade com a Lei Geral de Proteção de Dados, informamos que seus dados pessoais serão solicitados com a finalidade de acompanhar seu histórico de interações, manter você informado sobre nossos lançamentos e promoções, realizar pesquisas de opinião e satisfação e compartilhar seus dados com a imobiliária e o corretor parceiro, que irá te atender quando for autorizado. Seus dados serão mantidos em rigorosa política segurança e a qualquer momento, você poderá solicitar que seus dados pessoais sejam excluídos de nossos sistemas. A Benx Incorporadora não possui não possui qualquer parceria com outras empresas, sejam de móveis planejados, compra e venda de imóveis, veículos e afins. Os únicos produtos fornecidos por nós são os veiculados neste site e nas redes sociais descritas em seu rodapé. Caso receba algum contato/oferta com informação divergente da descrita acima, trata-se de fato inverídico e fraudulento. Caso passem por essa situação, por favor, entrem em contato conosco através do telefone ou e-mail: 11 4003-8503 | relacionamento@benx.com.br.
