INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('3c9be30e-84fe-4038-acb7-7500d1bb1ae2', 'viva-benx-vila-mascote', 'Viva Benx - Vila Mascote', 'Apartamentos de 34m² e 55m², com 2 e 3 dormitórios, opções com vaga e sem vaga, prontos para morar na Vila Mascote, com lazer completo e ótima localização.', 'his', 'pronto_para_morar', NULL, 'Empreendimento residencial com projeto pensado para unir conforto, praticidade e lazer completo em um bairro arborizado e bem localizado. O Viva Benx Vila Mascote oferece áreas comuns equipadas e decoradas, soluções Economix para economia condominial e plantas de 2 e 3 dormitórios com opções com vaga e sem vaga.', 'Jairo de Sender', 'Sergio Santana', 'Jairo de Sender', 300, 24, NULL, NULL, 2286.48, NULL, '34,13 m² e 55,95 m²', NULL, '2 e 3 dorms.', '144', 'Incorporação registrada sob o R.01 da matrícula 194.145, do 8º Cartório Oficial de Registro de Imóveis de São Paulo, em 14/11/2018. Todas as imagens utilizadas neste material são meramente ilustrativas. Os acabamentos, mobiliários, eletrodomésticos e demais itens do apartamento decorado e das perspectivas artísticas não fazem parte do Memorial Descritivo. Bem Imobiliária: Av. Dr. Cardoso de Melo, 1470 – Vila Olímpia – São Paulo – SP - Tel.: (11) 3847-1333 – CRECI: 20197-J. Os empreendimentos Viva Benx Casa do Ator, Viva Benx Chácara Santo Antônio, Viva Benx Pinheiros, Viva Benx Faria Lima, Viva Benx Vila Olímpia, Viva Benx Santana, Viva Benx Tatuapé, Viva Benx Mooca, Viva Benx Vila Mariana, Viva Benx Jardim Marajoara II, Viva Benx Jardim Marajoara I, Viva Benx Vila Mascote, Viva Benx Nações Unidas II, Viva Benx Nações Unidas I, Viva Benx Cambuci II, Viva Benx Cambuci I, Viva Benx Vila Leopoldina II, Viva Benx Vila Leopoldina possuem unidades enquadradas como HIS-2 (Habitação de Interesse Social) e/ou HMP (Habitação de Mercado Popular), destinadas a atender pessoas com renda familiar mensal de até 06 (seis) salários-mínimos (HIS-2) e 10 (dez) salários-mínimos (HMP). O preço de venda de unidade HIS-2 e HMP deverá observar os limites previstos na legislação, atualmente de R$ 369.600,00 e R$ 518.000,00, respectivamente, a serem anualmente atualizados pela variação do INCC, a partir de maio de 2025. Para mais informações sobre unidades e regras de enquadramentos, entrar em contato com um dos nossos consultores de venda.', 'Av. Túlio Teodoro de Campos, 6', 'Av. Túlio Teodoro de Campos, 6 - Vila Mascote, São Paulo/SP', '04360-040', NULL, NULL, 'https://m.uber.com/go/pickup?drop%5B0%5D=%7B%22addressLine1%22%3A%22Avenida%20T%C3%BAlio%20Teodoro%20de%20Campos%2C%206%20-%20Jabaquara%22%2C%22addressLine2%22%3A%22S%C3%A3o%20Paulo%20-%20SP%2C%2004360-040%22%2C%22id%22%3A%22c20589d6-b579-9fed-dd11-23a0277303a2%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.6394232%2C%22longitude%22%3A-46.6626822%2C%22provider%22%3A%22uber_places%22%7D&amp;marketing_vistor_id=904298d5-f2e2-4b76-9498-fdd3b39d18d9&amp;uclick_id=1235e595-2e34-4ae3-9f67-b17a615b07f1', 'https://www.google.com/maps/place/Av.+T%C3%BAlio+Teodoro+de+Campos,+6+-+Vila+Paulista,+S%C3%A3o+Paulo+-+SP,+04360-040/@-23.6388583,-