INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('2c79c34e-7b35-453e-8f14-7acab36345f5', 'viva-benx-nacoes-unidas-ii', 'Viva Benx - Nações Unidas II', 'Apartamentos de 33,67 m² com 1 ou 2 dormitórios, prontos para morar em Santo Amaro, com lazer completo e localização estratégica na Av. Nações Unidas.', 'his', 'pronto_para_morar', NULL, 'Empreendimento residencial em Santo Amaro com projeto voltado à praticidade, mobilidade e lazer completo. O Viva Benx Nações Unidas II reúne áreas comuns equipadas e decoradas, soluções Economix para economia condominial e plantas inteligentes de 33,67 m² com opção de 1 dormitório com sala ampliada.
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('5bfe8ff9-0a32-4e2a-a11b-271d58232967', 'simmetria-campo-belo', 'Simmetria Campo Belo', 'Um autêntico 3 suítes, como há muito tempo São Paulo não via. Perfeito nos mínimos detalhes.', NULL, 'pronto_para_morar', NULL, NULL, 'Pablo Slemenson', 'Escritório Burle Marx', 'João Armentano', NULL, NULL, NULL, NULL, NULL, NULL, '157m² a 161m²', NULL, '3 suítes', '2 a 3 vagas', 'Em conformidade com a Lei Geral de Proteção de Dados, informamos que seus dados pessoais serão solicitados com a finalidade de acompanhar seu histórico de interações, manter você informado sobre nossos lançamentos e promoções, realizar pesquisas de opinião e satisfação e compartilhar seus dados com a imobiliária e o corretor parceiro, que irá te atender quando for autorizado. Seus dados serão mantidos em rigorosa política segurança e a qualquer momento, você poderá solicitar que seus dados pessoais sejam excluídos de nossos sistemas. A Benx Incorporadora não possui não possui qualquer parceria com outras empresas, sejam de móveis planejados, compra e venda de imóveis, veículos e afins. Os únicos produtos fornecidos por nós são os veiculados neste site e nas redes sociais descritas em seu rodapé. Caso receba algum contato/oferta com informação divergente da descrita acima, trata-se de fato inverídico e fraudulento. Caso passem por essa situação, por favor, entrem em contato conosco através do e-mail: relacionamento@benx.com.br.', 'Rua Princesa Isabel, 1575', 'Rua Princesa Isabel, 1575 - Campo Belo, São Paulo/SP', '04601-003', NULL, NULL, 'https://m.uber.com/go/pickup?drop%5B0%5D=%7B%22addressLine1%22%3A%22Rua%20Princesa%20Isabel%2C%201575%20-%20Campo%20Belo%22%2C%22addressLine2%22%3A%22S%C3%A3o%20Paulo%20-%20SP%2C%2004601-003%22%2C%22id%22%3A%22516cb119-53b3-d922-57a1-b15ff18d58ae%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.613513%2C%22longitude%22%3A-46.675022%2C%22provider%22%3A%22uber_places%22%7D&amp;marketing_vistor_id=904298d5-f2e2-4b76-9498-fdd3b39d18d9&amp;uclick_id=67256e22-08e8-4fa6-afbc-a0e85001b10a', 'https://www.google.com/maps/place/R.+Princesa+Isabel,+1575+-+Campo+Belo,+S%C3%A3o+Paulo+-+SP,+04601-003/@-23.613454,-46.6773606,17z/data=!3m1!4b1!4m6!3m5!1s0x94ce50a6a2b6311d:0x9ce79ded8a5dcbe8!8m2!3d-23.613454!4d-46.6747857!16s%2Fg%2F11fjxytr8d!5m2!1e4!1e2?entry=ttu&amp;g_ep=EgoyMDI2MDUyMC4wIKXMDSoASAFQAw%3D%3D', 'https://www.waze.com/pt-BR/live-map/directions/br/sp/r.-princesa-isabel,-1575?to=place.ChIJHTG2oqZQzpQR6Mtdiu2d55w', 'wp/2026/05/SIMMETRIA-CAMPO-BELO-│-FACHADA-scaled.jpg', NULL, 'https://www.youtube.com/watch?v=ueqw8WZpEKc', 'wp/2026/05/Captura-de-tela-2026-05-26-171403.png', 'https://conteudo.benx.com.br/_tour/simmetria/', NULL, NULL, NULL, NULL, NULL, NULL, true, false, true, true, false, '[]', '[{"nome": "Área comum 1", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-ACADEMIA-scaled.jpg"}, {"nome": "Área comum 2", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-BRINQUEDOTECA-scaled.jpg"}, {"nome": "Área comum 3", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-HALL-PE-DIREITO-DUPLO-scaled.jpg"}, {"nome": "Área comum 4", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-JARDIM-ESPELHO-DAGUA-scaled.jpg"}, {"nome": "Área comum 5", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-LIVING-DECORADO-2-scaled.jpg"}, {"nome": "Área comum 6", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-LIVING-DECORADO-scaled.jpg"}, {"nome": "Área comum 7", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-LOUNGE-scaled.jpg"}, {"nome": "Área comum 8", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-PISCINA-COBERTA.jpg"}, {"nome": "Área comum 9", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-PLAYGROUND-scaled.jpg"}, {"nome": "Área comum 10", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-PRACA-INTERNA-scaled.jpg"}, {"nome": "Área comum 11", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-QUADRA-scaled.jpg"}, {"nome": "Área comum 12", "imagem": "wp/2026/05/SIMMETRIA-CAMPO-BELO-│-SPA-scaled.jpg"}]', '[]', '[]', '[]', '629fce57-d783-4d19-9216-cbb93ca47d26', '323acf6f-f731-4e88-89c7-b08cf48474a9', '52a9fa5a-17de-42bd-80e8-3981715ec6e7', '9ada1ef9-9370-429b-9811-333d627580cc', '2026-06-04 00:35:47.333335', '2026-06-04 02:21:02.585', NULL, NULL, '[]', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('deb5412a-7374-4178-900b-f619550cac4b', 'viva-benx-faria-lima', 'Viva Benx - Faria Lima', 'Apartamentos de 24 m² a 28 m² com 1 dormitório, em Pinheiros, prontos para morar, com lazer completo e mobilidade privilegiada perto da estação Faria Lima.', 'his', 'pronto_para_morar', NULL, 'Empreendimento residencial em Pinheiros com projeto contemporâneo, lazer distribuído em três pavimentos e soluções inteligentes para o dia a dia. O Viva Benx Faria Lima combina localização estratégica, áreas comuns equipadas e decoradas e unidades compactas pensadas para conforto e praticidade.', 'Jonas Birger', 'Roberto Riscala', 'Mestisso', 251, 28, NULL, 1, 1948.89, NULL, '24 m² a 28 m²', NULL, '1 dorm.', 'Sem Vagas', 'Incorporação Imobiliária do Viva Benx Faria Lima registrada sob o R.3 da Matrícula nº 158.531, do 10º Oficial de Registro de Imóveis de São Paulo-SP, em 02/06/2021. Os acabamentos, o mobiliário, os eletrodomésticos e os demais itens do apartamento decorado e das perspectivas não fazem parte do Memorial Descritivo. A vegetação que compõe o paisagismo retratado nas perspectivas é meramente ilustrativa e apresenta porte adulto de referência. Na entrega do empreendimento, essa vegetação poderá apresentar diferenças de tamanho e porte, mas estará de acordo com o Projeto Paisagístico. A vista apresentada nas imagens é meramente ilustrativa, não sendo a fotografia exata do local. Material preliminar, sujeito à alteração. Intermediação: Bem Imobiliária - Av. Dr. Cardoso de Melo, 1.470, Vila Olímpia, São Paulo/SP - Tel.: (11) 3847-1333 - Creci: 20.197-J. Os empreendimentos Viva Benx Casa do Ator, Viva Benx Chácara Santo Antônio, Viva Benx Pinheiros, Viva Benx Faria Lima, Viva Benx Vila Olímpia, Viva Benx Santana, Viva Benx Tatuapé, Viva Benx Mooca, Viva Benx Vila Mariana, Viva Benx Jardim Marajoara II, Viva Benx Jardim Marajoara I, Viva Benx Vila Mascote, Viva Benx Nações Unidas II, Viva Benx Nações Unidas I, Viva Benx Cambuci II, Viva Benx Cambuci I, Viva Benx Vila Leopoldina II, Viva Benx Vila Leopoldina e Viva Benx Lapa possuem unidades enquadradas como HMP (Habitação de Mercado Popular), destinadas às pessoas com renda familiar mensal de até 10 (dez) salários-mínimos, e terão preço de venda de até R$ 537.672,71 e/ou HIS-2 (Habitação de Interesse Social), destinadas às pessoas com renda familiar mensal de até 06 (seis) salários-mínimos, e terão preço de venda de até R$ 383.636,74. Os preços de venda serão corrigidos anualmente pelo Índice Nacional de Custo da Construção – INCC, a partir de janeiro de 2026.
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('13148091-2e36-4d64-8200-aa246b246d74', 'viva-benx-santana', 'Viva Benx - Santana', 'Apartamentos de 1, 2 e 3 dormitórios com lazer completo e localização privilegiada a poucos metros do metrô Parada Inglesa.', 'his', 'pronto_para_morar', NULL, 'Empreendimento com lazer completo equipado e decorado, torre única e excelente mobilidade na Zona Norte de São Paulo.
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('313edce3-d05c-41b5-849b-9c07e3102aed', 'viva-benx-chacara-santo-antonio', 'Viva Benx - Chácara Santo Antônio', NULL, 'his', 'pronto_para_morar', NULL, 'O Viva Benx Chácara Santo Antônio foi desenvolvido para oferecer moradia acessível com infraestrutura completa em uma das regiões mais estratégicas da zona sul de São Paulo. O empreendimento reúne unidades compactas e funcionais, aliadas a uma ampla área de lazer e serviços compartilhados, proporcionando praticidade no dia a dia. Inserido em uma região com fácil acesso à Marginal Pinheiros e próximo a estações de transporte público, o projeto valoriza mobilidade, conveniência e qualidade de vida, seguindo o conceito de eficiência e economia da ', 'PSA Arquitetura', 'Sergio Santana', 'Jairo de Sender', 435, NULL, NULL, 2, 3847.33, NULL, '34,35, 37,09m², 52,96m²', NULL, '2 e 3 dorms.', '68', 'Incorporação Imobiliária do Viva Benx Chácara Santo Antônio registrada sob o R.19 da Matrícula 180.403 do 11o Cartório de Imóveis de São Paulo, em 29/10/2020. Intermediação: Bem Imobiliária – Av. Dr. Cardoso de Melo, 1.340 – Vila Olímpia – São Paulo – SP - Tel:. (11) 3842- 1333 – Creci 20197-J. Todas as imagens utilizadas são meramente ilustrativas. Os acabamentos, o mobiliário, os eletrodomésticos e os demais itens do apartamento decorado e das perspectivas não fazem parte do Memorial Descritivo. A vegetação que compõe o paisagismo retratado nas perspectivas é meramente ilustrativa e apresenta porte adulto de referência. Na entrega do empreendimento, essa vegetação poderá apresentar diferenças de tamanho e porte, mas estará de acordo com o projeto paisagístico e em conformidade com as aprovações ambientais. A vista apresentada nas imagens é meramente elucidativa, não sendo a fotografia exata do local. Os empreendimentos Viva Benx Casa do Ator, Viva Benx Chácara Santo Antônio, Viva Benx Pinheiros, Viva Benx Faria Lima, Viva Benx Vila Olímpia, Viva Benx Santana, Viva Benx Tatuapé, Viva Benx Mooca, Viva Benx Vila Mariana, Viva Benx Jardim Marajoara II, Viva Benx Jardim Marajoara I, Viva Benx Vila Mascote, Viva Benx Nações Unidas II, Viva Benx Nações Unidas I, Viva Benx Cambuci II, Viva Benx Cambuci I, Viva Benx Vila Leopoldina II, Viva Benx Vila Leopoldina possuem unidades enquadradas como HIS-2 (Habitação de Interesse Social) e/ou HMP (Habitação de Mercado Popular), destinadas a atender pessoas com renda familiar mensal de até 06 (seis) salários-mínimos (HIS-2) e 10 (dez) salários-mínimos (HMP). O preço de venda de unidade HIS-2 e HMP deverá observar os limites previstos na legislação, atualmente de R$ 369.600,00 e R$ 518.000,00, respectivamente, a serem anualmente atualizados pela variação do INCC, a partir de maio de 2025. Para mais informações sobre unidades e regras de enquadramentos, entrar em contato com um dos nossos consultores de venda.
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('fbd5bcc7-fe4a-434d-8de1-498c7bd87c07', 'jha-corporate-boutique', 'JHA Corporate Boutique', 'Edifício corporativo boutique no Itaim Bibi, com lajes de 605,63 m² a 826,50 m², projeto autoral, rooftop e foco em sofisticação, exclusividade e sustentabilidade.', NULL, 'em_construcao', NULL, 'Projeto corporativo no conceito Corporate Boutique, pensado para um estilo de vida plural, cosmopolita e moderno, com arquitetura autoral e olhar mais humano para espaços corporativos.
