INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('51a2d674-7686-41da-843e-de3f7c7fd2f9', 'brooklin-skymark', 'Brooklin Skymark', 'Aqui, os momentos de entretenimento ou contemplação serão incomparáveis. Afinal, só quem vive no Skymark tem o privilégio de contar com uma área de diversão e relaxamento com vista panorâmica para o melhor da zona sul de São Paulo.', NULL, 'pronto_para_morar', NULL, 'A Benx traz para o Skymark o exclusivo conceito rooftop, que traz o lazer ao terraço do prédio, propiciando um espaço único para o convívio social e a prática de esportes.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '65m² e 77m²', NULL, '2 e 3 dorms com suíte', NULL, 'Em conformidade com a Lei Geral de Proteção de Dados, informamos que seus dados pessoais serão solicitados com a finalidade de acompanhar seu histórico de interações, manter você informado sobre nossos lançamentos e promoções, realizar pesquisas de opinião e satisfação e compartilhar seus dados com a imobiliária e o corretor parceiro, que irá te atender quando for autorizado. Seus dados serão mantidos em rigorosa política segurança e a qualquer momento, você poderá solicitar que seus dados pessoais sejam excluídos de nossos sistemas. A Benx Incorporadora não possui não possui qualquer parceria com outras empresas, sejam de móveis planejados, compra e venda de imóveis, veículos e afins. Os únicos produtos fornecidos por nós são os veiculados neste site e nas redes sociais descritas em seu rodapé. Caso receba algum contato/oferta com informação divergente da descrita acima, trata-se de fato inverídico e fraudulento. Caso passem por essa situação, por favor, entrem em contato conosco através do e-mail: relacionamento@benx.com.br.', 'Rua Min. Luis Galotti, 74', 'Rua Min. Luis Galotti, 74 - Brooklin, São Paulo/SP', '04580-050', NULL, NULL, 'https://m.uber.com/go/pickup?drop%5B0%5D=%7B%22addressLine1%22%3A%22R.%20Min.%20Luiz%20Gallotti%2C%2074%22%2C%22addressLine2%22%3A%22-%20Vila%20Cordeiro%2C%20S%C3%A3o%20Paulo%20-%20SP%22%2C%22id%22%3A%22ChIJ9VZzQL5QzpQRVoZr6J20VBY%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.6221814%2C%22longitude%22%3A-46.6863338%2C%22provider%22%3A%22google_places%22%7D&amp;marketing_vistor_id=904298d5-f2e2-4b76-9498-fdd3b39d18d9&amp;uclick_id=c7dac8be-4d69-4318-8d41-f0905302da55', 'https://www.google.com/maps/place/R.+Min.+Luiz+Gallotti,+74+-+Vila+Cordeiro,+S%C3%A3o+Paulo+-+SP,+04580-050/@-23.6221814,-46.6889087,17z/data=!3m1!4b1!4m6!3m5!1s0x94ce50be407356f5:0x1654b49de86b8656!8m2!3d-23.6221814!4d-46.6863338!16s%2Fg%2F11gf9lyq8_!5m2!1e4!1e2?entry=ttu&amp;g_ep=EgoyMDI2MDUyMC4wIKXMDSoASAFQAw%3D%3D', 'https://www.waze.com/pt-BR/live-map/directions/br/sp/r.-min.-luiz-gallotti,-74?to=place.ChIJ9VZzQL5QzpQRVoZr6J20VBY', 'wp/2026/05/BROOKLIN-SKYMARK-│-ENTRADA.jpg', NULL, 'https://www.youtube.com/watch?v=NEMVQ-cdFY8', 'wp/2026/05/Captura-de-tela-2026-05-25-160110.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, false, true, true, false, '[]', '[{"nome": "Área comum 1", "imagem": "wp/2026/05/BROOKLIN-SKYMARK-│-ACADEMIA.jpg"}, {"nome": "Área comum 2", "imagem": "w