INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('a2290e99-b94e-4f9b-8f79-4b7b0505be1f', 'the-frame', 'The Frame', 'O Empreendimento mais completo, no melhor da Vila Nova Conceição', NULL, 'pronto_para_morar', NULL, 'The Frame é viver no endereço mais desejado de São Paulo.
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('04b945f3-0fa7-4d34-9ffe-c973a0fc474f', 'butanta', 'Viva Benx - Butantã', 'Viva mais em uma planta sob medida, por menos custo para o seu bolso.', 'his_e_hmp', 'em_construcao', NULL, 'O Viva Benx Butantã foi concebido para oferecer uma experiência completa de moradia, unindo arquitetura inteligente, lazer diferenciado e localização estratégica. Com torres modernas e plantas bem distribuídas, o projeto prioriza funcionalidade, conforto e otimização dos espaços para o dia a dia. As áreas comuns foram pensadas para atender diferentes estilos de vida, com opções de lazer no térreo e na cobertura, promovendo convivência, bem-estar e praticidade.', 'Rodrigo Sobreiro Arquitetos', 'Rossin & Tramontina', 'Maria Clara Marback', 336, 18, 9, 2, 2278, NULL, '31 a 55m²', NULL, '1 e 2 Dorms.', '12 para carros  e 20 para motos', 'Empreendimento: Viva Benx Butantã. Incorporadora: M.A.R. Versalhes Desenvolvimento Imobiliário SPE LTDA. Memorial de Incorporação registrado sob o R.04. na Matrícula nº 286.931, do 18º Oficial de Registro de Imóveis de São Paulo, em 08/03/2024. Os acabamentos, o mobiliário, os eletrodomésticos e os demais itens do apartamento decorado e das perspectivas não fazem parte do Memorial Descritivo. A vegetação que compõe o paisagismo retratado nas perspectivas é meramente ilustrativa e apresenta porte adulto de referência. Na entrega do empreendimento, essa vegetação poderá apresentar diferenças de tamanho e porte, mas estará de acordo com o Projeto Paisagístico e em conformidade com as aprovações ambientais. A vista apresentada nas imagens é meramente elucidativa, não sendo a fotografia exata do local. Material preliminar, sujeito à alteração. Intermediação: Bem Imobiliária: Av. Dr. Cardoso de Melo, 1.470, Vila Olímpia, São Paulo/SP. Tel.: (11) 3847-1333. Creci: 20.197-J. CENTRAL DE ATENDIMENTO ABYARA (Quantun Partners Intermediação Imobiliária Ltda): Av. Ibirapuera, 2332, 5º Andar, Bloco 1, Edifício Torre Ibirapuera I, Indianópolis, SP. CEP: 04028-002 – Tel.: 3888-9201 – diariamente até às 21:00 horas – CNPJ: 49.433.651/0001-64 – CRECI 42766-J. As unidades finais 08 e 09, localizadas no pavimento térreo da Torre A, finais 01 a 09, localizadas do 6º ao 17º pavimento da Torre A, finais 07 a 09 do pavimento térreo, da Torre B, finais 01, 06 a 12, localizadas do 1º ao 14º Pavimento, da Torre B, e finais 01 a 05, 11 e 12, localizadas no 15º pavimento da Torre B, são unidades HIS-2 (Habitação de Interesse Social), destinadas às pessoas com renda familiar mensal de até 06 (seis) salários-mínimos, e terão preço de venda de até R$ 383.636,74. As unidades finais 05 e 06, localizadas no pavimento térreo, da Torre B, finais 03 a 05, do 1º pavimento, da Torre B, e finais 02 a 05, localizadas do 2º pavimento ao 14º pavimento, da Torre B, são unidades HMP (Habitação de Mercado Popular), destinadas às pessoas com renda familiar mensal de até 10 (dez) salários-mínimos, e terão preço de venda de até R$ 537.672,71. Os preços de venda serão corrigidos anualmente pelo Índice Nacional de Custo da Construção – INCC, a partir de janeiro de 2026.', 'Rua Desembargador Armando Fairbanks, 199', 'Rua Desembargador Armando Fairbanks, 199', '05501-040', 'Av. Valdemar Ferreira, 280', 'Av. Valdemar Ferreira, 280', 'https://m.uber.com/go/home?drop%5B0%5D=%7B%22addressLine1%22%3A%22Viva%20Benx%20Butant%C3%A3%22%2C%22addressLine2%22%3A%22R.%20Des.%20Armando%20Fairbanks%2C%20199%20-%20Butant%C3%A3%2C%20S%C3%A3o%20Paulo%20-%20SP%22%2C%22id%22%3A%22ChIJ0bdTTABXzpQRc6yUN4ZFEnw%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.571633400000003%2C%22longitude%22%3A-46.7044773%2C%22provider%22%3A%22google_places%22%7D&amp;marketing_vistor_id=904298d5-f2e2-4b76-9498-fdd3b39d18d9&amp;uclick_id=234a1efd-c2e9-4f29-a9ae-b3dcb880a591', 'https://www.google.com/maps/search/?api=1&amp;query=Av+Valdemar+Ferreira,+280,+S%C3%A3o+Paulo,+SP', 'https://waze.com/ul?q=Av.+Valdemar+Ferreira,+280,+S%C3%A3o+Paulo,+SP', 'wp/2026/03/BENX_Butanta-15-SPA_HR1.webp', 'wp/2026/03/vivabenx-butanta.png', 'https://youtu.be/-IPzd3gRBPM', 'wp/2026/03/Thumb-Butanta.jpg', 'https://tour.piperz.io/eEESpv2vZQb', 'https://vr360.s3.amazonaws.com/tour/BENX/Klabin-V4/index.html', NULL, NULL, NULL, NULL, NULL, true, false, true, true, false, '["Portaria com vidro blindado.", "Lobby com pé direito duplo"]', '[{"nome": "Lobby"}, {"nome": "Salão de Festas"}, {"nome": "Brinquedoteca"}, {"nome": "Academia"}, {"nome": "Churrasqueiras"}, {"nome": "Coworking"}, {"nome": "Salão de Jogos"}, {"nome": "Playground"}, {"nome": "Piscina adulto com Deck Molhado"}, {"nome": "Solarium"}, {"nome": "Piscina Infantil"}, {"nome": "Pet  Place e Pet Care"}, {"nome": "Minimarket"}, {"nome": "Bicicletário"}, {"nome": "Sala para Delivery"}, {"nome": "Lavanderia"}, {"nome": "Mirante SPA"}, {"nome": "Horta"}, {"nome": "Redário"}, {"nome": "Área comum 1", "imagem": "wp/2026/03/BENX_Butanta-13-PET-PLACE_HR0.webp"}, {"nome": "Área comum 2", "imagem": "wp/2026/03/BENX_Butanta-01-PET-CARE_HR0.webp"}, {"nome": "Área comum 3", "imagem": "wp/2026/03/BENX_Butanta-03-BRINQUEDO