INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('ccde5a0f-80a2-42bd-b617-d6c46ed2a691', 'viva-benx-nacoes-unidas-i', 'Viva Benx - Nações Unidas I', 'Apartamentos de 2 dormitórios com opção de 1 dormitório com sala ampliada, em condomínio com lazer completo próximo à Av. das Nações Unidas.', 'his', 'pronto_para_morar', NULL, 'Empreendimento com lazer completo equipado e decorado, localizado próximo a importantes vias da cidade, com fácil acesso à Marginal Pinheiros.', 'Rubio & Luongo', 'Sergio Santana', 'Rosenbaum', NULL, NULL, NULL, NULL, NULL, NULL, '33,67m2', NULL, '1 e 2 Dorms', NULL, ' Incorporação Imobiliária do Viva Benx Nações Unidas I registrada sob o R.3 da matrícula n° 445.435 do 4º Cartório de Registro de Imóveis de São Paulo/SP. Os acabamentos, o mobiliário, os eletrodomésticos e os demais itens do apartamento decorado e das perspectivas não fazem parte do Memorial Descritivo. A vegetação que compõe o paisagismo retratado nas perspectivas é meramente ilustrativa e apresenta porte adulto de referência. Na entrega do empreendimento, essa vegetação poderá apresentar diferenças de tamanho e porte, mas estará de acordo com o Projeto Paisagístico e em conformidade com as aprovações ambientais. A vista apresentada nas imagens é meramente elucidativa, não sendo a fotografia exata do local. Material preliminar, sujeito à alteração. Intermediação: Bem Imobiliária - Av. Dr. Cardoso de Melo, 1.470, Vila Olímpia, São Paulo/SP - Tel.: (11) 3847-1333 - Creci: 20.197-J. Os empreendimentos Viva Benx Casa do Ator, Viva Benx Chácara Santo Antônio, Viva Benx Pinheiros, Viva Benx Faria Lima, Viva Benx Vila Olímpia, Viva Benx Santana, Viva Benx Tatuapé, Viva Benx Mooca, Viva Benx Vila Mariana, Viva Benx Jardim Marajoara II, Viva Benx Jardim Marajoara I, Viva Benx Vila Mascote, Viva Benx Nações Unidas II, Viva Benx Nações Unidas I, Viva Benx Cambuci II, Viva Benx Cambuci I, Viva Benx Vila Leopoldina II, Viva Benx Vila Leopoldina e Viva Benx Lapa possuem unidades enquadradas como HMP (Habitação de Mercado Popular), destinadas às pessoas com renda familiar mensal de até 10 (dez) salários-mínimos, e terão preço de venda de até R$ 537.672,71 e/ou HIS-2 (Habitação de Interesse Social), destinadas às pessoas com renda familiar mensal de até 06 (seis) salários-mínimos, e terão preço de venda de até R$ 383.636,74. Os preços de venda serão corrigidos anualmente pelo Índice Nacional de Custo da Construção – INCC, a partir de janeiro de 2026.', 'Av. Nações Unidas, 21381', 'Av. Nações Unidas, 21381 - JD Dom Bosco, São Paulo/SP', '04753-100', NULL, NULL, 'https://m.uber.com/go/pickup?drop%5B0%5D=%7B%22addressLine1%22%3A%22Avenida%20das%20Na%C3%A7%C3%B5es%20Unidas%2C%2021381%20-%20Campo%20Grande%22%2C%22addressLine2%22%3A%22S%C3%A3o%20Paulo%20-%20SP%2C%2004696-005%22%2C%22id%22%3A%22d1b71cde-afa8-fd7a-d237-3e919d85c163%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.668756%2C%22longitude%22%3A-46.7046267%2C%22provider%22%3A%22uber_places%22%7D&amp;marketing_vistor_id=904298d5-f2e2-4b76-9498-fdd3b39d18d9&amp;uclick_id=1235e595-2e34-4ae3-9f67-b17a615b07f1', 'https://www.google.com/maps/place/Av.+das+Na%C3%A7%C3%B5es+Unidas,+21381+-+Jurubatuba,+S%C3%A3o+Paulo+-+SP,+04696-005/@-23.668027,-46.707463,17z/data=!3m1!4b1!4m6!3m5!1s0x94ce5035f85eab01:0x36958d17989545f0!8m2!3d-23.668027!4d-46.7048881!16s%2Fg%2F11jnsr3pjm!5m2!1e4!1e2?entry=ttu&amp;g_ep=EgoyMDI2MDQyNy4wIKXMDSoASAFQAw%3D%3D', 'https://www.waze.com/pt-BR/live-map/directions/br/sp/av.-das-nacoes-unidas,-21381?to=place.ChIJAate-DVQzpQR8EWVmBeNlTY', 'wp/2026/04/VIVA-BENX-NACOES-UNIDAS-1-│-PISCINA.jpg', 'wp/2026/04/Captura-de-tela-2026-05-06-183229.png', 'https://www.youtube.com/watch?v=I895kmml4dI', 'wp/2026/04/Captura-de-tela-2026-05-05-183111.png', 'https://conteudo.benx.com.br/_tour/nacoesunidas/', NULL, NULL, NULL, NULL, NULL, NULL, true, false, true, true, false, '["Portaria única com controle de acesso", "Elevadores com chamada inteligente", "Lâmpadas LED", "Sensores de presença", "Captação de água da chuva", "Lobby com pé direito duplo"]', '[{"nome": "Bicicletário"}, {"nome": "Lobby"}, {"nome": "Quadra recreativa"}, {"nome": "Churrasqueira"}, {"nome": "Playground"}, {"nome": "Academia"}, {"nome": "Salão de festas"}, {"nome": "Brinquedoteca"}, {"nome": "Salão de jogos"}, {"nome": "Bosque"}, {"nome": "Lavanderia"}, {"nome": "Praça contemplativa"}, {"nome": "Loja"}, {"nome": "Brinquedoteca"}, {"nome": "Área comum 1", "imagem": "wp/2026/04/VIVA-BENX-NACOES-UNIDAS-1-│-AREA-VERDE.jpg"}, {"nome": "Área comum 2", "imagem": "wp/2026/04/VIVA-BENX-NACOES-UNIDAS-1-│-BICICLETARIO.jpg"}, {"nome": "Área comum 3", "imagem": "wp/2026/04/VIVA-BENX-NACOES-UNIDAS-1-│-BRINQUEDOTECA.jpg"}, {"nome": "Área comum 4", "imagem": "wp/2026/04/VIVA-BENX-NACOES-UNIDAS-1-│-ESPACO-GOURMET.jpg"}, {"nome": "Área comum 5", "imagem": "wp/2026/04/VIVA-BENX-NACOES-UNIDAS-1-│-FITNESS.jpg"}, {"nome": "Área comum 6", "imagem": "wp/2026/04/VIVA-BENX-NACOES-UNIDAS-1-│-HALL.jpg"}, {"nome": "Área comum 7", "imagem": "wp/2026/04/VIVA-BENX-NACOES-UNIDAS-1-│-LAVANDERIA.jpg"}, {"nome": "Área comum 8", "imagem": "wp/2026/04