INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('588e2c2b-b39b-4a0e-a705-50b556371e12', 'viz-ponte-estaiada', 'Viz Ponte Estaiada', 'Inovador em localização, estilo e conforto. Ao lado do Cidade Jardim e a poucos minutos da Berrini e do MorumbiShopping. Sua vida integrada ao mais importante eixo empresarial de São Paulo, com infraestrutura privilegiada de compras e serviços.', NULL, 'pronto_para_morar', NULL, 'Um empreendimento com vista espetacular para o skyline da Marginal Pinheiros, acesso estratégico a qualquer região de São Paulo e com uma série de serviços que vão proporcionar uma experiência única de vida aos seus moradores. Tudo isso em uma localização privilegiada: entre o Cidade Jardim e o Parque Global.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '35m² ou 70m²', NULL, '1 e 2 dorms', '1 e 2 vagas', 'Em conformidade com a Lei Geral de Proteção de Dados, informamos que seus dados pessoais serão solicitados com a finalidade de acompanhar seu histórico de interações, manter você informado sobre nossos lançamentos e promoções, realizar pesquisas de opinião e satisfação e compartilhar seus dados com a imobiliária e o corretor parceiro, que irá te atender quando for autorizado. Seus dados serão mantidos em rigorosa política segurança e a qualquer momento, você poderá solicitar que seus dados pessoais sejam excluídos de nossos sistemas. A Benx Incorporadora não possui não possui qualquer parceria com outras empresas, sejam de móveis planejados, compra e venda de imóveis, veículos e afins. Os únicos produtos fornecidos por nós são os veiculados neste site e nas redes sociais descritas em seu rodapé. Caso receba algum contato/oferta com informação divergente da descrita acima, trata-se de fato inverídico e fraudulento. Caso passem por essa situação, por favor, entrem em contato conosco através do e-mail: relacionamento@benx.com.br.', 'Rua Cesar Vallejo, 100', 'Rua Cesar Vallejo, 100 - Real Parque, São Paulo/SP', '05685-000', NULL, NULL, 'https://m.uber.com/go/pickup?drop%5B0%5D=%7B%22addressLine1%22%3A%22R.%20Cesar%20Vallejo%2C%20100%20-%20Morumbi%22%2C%22addressLine2%22%3A%22S%C3%A3o%20Paulo%20-%20SP%2C%2005685-000%22%2C%22id%22%3A%22565dc89e-4a77-3b6b-863c-bf6f2f84dd15%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.6069768%2C%22longitude%22%3A-46.701357%2C%22provider%22%3A%22uber_places%22%7D&amp;marketing_vistor_id=904298d5-f2e2-4b76-9498-fdd3b39d18d9&amp;uclick_id=c7dac8be-4d69-4318-8d41-f0905302da55', 'https://www.google.com/maps/place/R.+C%C3%A9sar+Vallejo,+100+-+Real+Parque,+S%C3%A3o+Paulo+-+SP,+05685-000/@-23.6067052,-46.7037255,17z/data=!3m1!4b1!4m6!3m5!1s0x94ce572da5ddcf81:0x55750982a037e59a!8m2!3d-23.6067052!4d-46.7011506!16s%2Fg%2F11kj6qv8mn!5m2!1e4!1e2?entry=ttu&amp;g_ep=EgoyMDI2MDUyMC4wIKXMDSoASAFQAw%3D%3D', 'https://www.waze.com/pt-BR/live-map/directions/br/sp/r.-cesar-vallejo,-100?to=place.ChIJgc_dpS1XzpQRmuU3oIIJdVU', 'wp/2026/05/VIZ-PONTE-ESTAIADA-│-PISCINA-AEREA.jpg', NULL, 'https://www.youtube.com/watch?v=p8KM2oFNQx0', 'wp/2026/05/Captura-de-tela-2026-05-25-174659.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL,