INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('e33cc682-59ad-4e57-9e1d-12246c44e39c', 'star-conceicao', 'Viva benx - Star Conceição', 'VIVA BENX STAR. Faz bem-estar em casa.', 'hmp', 'pronto_para_morar', NULL, 'O Viva Benx Star Conceição reúne localização estratégica na Zona Sul de São Paulo, próximo ao metrô e principais vias, com infraestrutura completa ao redor. O empreendimento oferece lazer equipado e decorado, além de soluções sustentáveis que reduzem custos e impactam positivamente o meio ambiente. Os apartamentos contam com diferenciais funcionais e modernos, enquanto o condomínio traz comodidades que elevam o conforto, a praticidade e o bem-estar no dia a dia.', 'MCAA Arquitetos', 'Marcelo Novaes', 'Chris Silveira', 193, 19, 12, 1, 1913, NULL, 'Studios, 42, 44 e 56m²', NULL, '1, 2 e 3 dorms.', '33 Vagas', 'Empreendimento: Viva Benx Star Conceição. Incorporadora: M.A.R. Hidra Desenvolvimento Imobiliário SPE Ltda. Memorial de incorporação registrado sob o R.4 da matrícula nº 182.757 do 8º Oficial de Registro de Imóveis de São Paulo, em 22/10/2021. Os acabamentos, mobiliário, eletrodomésticos e demais itens do apartamento decorado e das perspectivas não fazem parte do Memorial Descritivo. A vegetação apresentada é ilustrativa e poderá sofrer variações, conforme o Projeto Paisagístico e aprovações ambientais. As imagens são meramente ilustrativas. Material preliminar, sujeito a alterações. Intermediação: Bem Imobiliária – Av. Dr. Cardoso de Melo, 1.470, Vila Olímpia, São Paulo/SP – Tel.: (11) 3847-1333 – Creci: 20.197-J. Central de Atendimento Abyara (Quantun Partners Intermediação Imobiliária Ltda) – Av. Ibirapuera, 2332, 5º andar, Bloco 1, Edifício Torre Ibirapuera I, Indianópolis, CEP: 04028-002, São Paulo/SP. Atendimento diário até às 21h. CNPJ: 49.433.651/0001-64 | Creci: 42766-J. As unidades finais 1 ao 6, do 5º ao 19º pavimento; finais 8, 9, 10 e 11, do 3º ao 17º pavimento; finais 8 e 9, do 2º, 18º e 19º pavimento; e finais 10 e 11, do 19º pavimento são unidades HMP, destinadas a renda familiar de até 10 salários-mínimos, com preço de venda de até R$ 537.672,71. Os valores serão corrigidos anualmente pelo INCC a partir de janeiro de 2026.', 'Rua Itatiaia, 201', 'Rua Itatiaia, 201 - Vila Guarani - São Paulo/SP', '04310-010', 'Rua Itatiaia, 02', NULL, 'https://m.uber.com/go/pickup?drop%5B0%5D=%7B%22addressLine1%22%3A%22Viva%20Benx%20Star%20Concei%C3%A7%C3%A3o%22%2C%22addressLine2%22%3A%22R.%20Itatiaia%2C%20201%20-%20Concei%C3%A7%C3%A3o%20-%20S%C3%A3o%20Paulo%20-%20SP%2C%2004310-010%22%2C%22id%22%3A%22dd58f019-948b-4cf1-a2c0-bbaa84fe740c%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.63153%2C%22longitude%22%3A-46.639765%2C%22provider%22%3A%22uber_places%22%7D&amp;marketing_vistor_id=904298d5-f2e2-4b76-9498-fdd3b39d18d9&amp;uclick_id=1235e595-2e34-4ae3-9f67-b17a615b07f1', 'https://www.google.com/maps/search/?api=1&amp;query=R.+Itatiaia,+201+-+Vila+Guarani+(Zona+Sul),+S%C3%A3o+Paulo+-+SP', 'https://www.waze.com/ul?q=R.+Itatiaia,+201,+S%C3%A3o+Paulo&amp;navigate=yes', 'wp/2026/03/VivaBenx_Star_Conceicao_AcessoPrincipal-2.webp', 'wp/202