INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('ab108715-ac53-4953-b029-a12960ada402', 'parque-global-pg-residences', 'Parque Global - PG Residences', 'O MAIOR BAIRRO PLANEJADO DA AMÉRICA LATINA RECEBE A TORRE MAIS ALTA DE SÃO PAULO', NULL, 'em_construcao', NULL, 'TORRE RESIDENCIAL INSERIDA NO MASTERPLAN PARQUE GLOBAL, UMA NOVA SMART CITY EM SÃO PAULO, COM CONCEITO MIXED USE E INTEGRAÇÃO ENTRE MORADIA, SERVIÇOS, MOBILIDADE, ÁREAS VERDES E CONVENIÊNCIA.', 'RAF ARQUITETURA', 'ENEA Landscape Architecture Design | Cardim Arquitetura Paisagística', 'Hirsch Bedner Associates (HBA Miami) | Debora Aguiar', 300, 45, NULL, 1, 5918.00, NULL, NULL, NULL, NULL, '534 vagas', 'Projeto de construção do empreendimento conforme Alvará de Aprovação de Edificação Nova nº 2013/27407-00, expedido pela Municipalidade de São Paulo em 3/10/2013; promoveu o registro do Memorial de Incorporação no 15º Oficial de Registro de Imóveis de São Paulo, conforme R.03/M.220.869 de 23/10/2013, transportado conforme a Av.01/M.225.471 de 27/1/2014, revalidada sob a Av.7/M.225.471 de 27/4/2020; aprovou perante a Prefeitura Municipal o projeto modificativo de construção do empreendimento, conforme Projeto Modificativo de Alvará de Aprovação e Execução de Edificação Nova nº 2013-27407-02, publicado pela Municipalidade de São Paulo em 28/8/2020, e promoveu o registro da rerratificação e revalidação do Memorial de Incorporação no 15º Oficial de Registro de Imóveis de São Paulo, averbado sob a Av.9/M.225.471 de 18/9/2020; lançou as normas da Convenção de Condomínio por meio de instrumento particular, que integra o Memorial de Incorporação acima referido. O empreendimento Shopping Center será objeto de aprovação de projeto legal na Prefeitura Municipal de São Paulo. Após aprovação, a incorporadora promoverá o registro da incorporação imobiliária no 15º Cartório de Registro de Imóveis da Comarca de São Paulo – SP. O empreendimento somente será comercializado após o registro da Memorial de Incorporação no referido cartório de registro de imóveis, nos termos da Lei nº 4.591/64. O empreendimento Complexo de Inovação, Saúde e Educação será objeto de aprovação de projeto legal perante a Prefeitura Municipal de São Paulo. Após aprovação, a incorporadora promoverá o registro da incorporação imobiliária no 15º Cartório de Registro de Imóveis da Comarca de São Paulo – SP. O empreendimento somente será comercializado após o registro do Memorial de Incorporação no referido cartório de registro de imóveis, nos termos da Lei nº 4.591/64. Todas as imagens e perspectivas contidas neste material são meramente ilustrativas e poderão sofrer alterações, inclusive quanto a forma, cor, textura, posição e tamanho. As unidades autônomas e áreas comuns do empreendimento serão entregues conforme Projeto Legal, Memorial de Incorporação e Memorial Descritivo de Acabamento do empreendimento, que prevalecerão em caso de conflito com qualquer outro material ou informação relativa ao empreendimento. Imagem da vista aérea – A perspectiva ilustrada da vista aérea do empreendimento é meramente ilustrativa. O Complexo de Inovação, Saúde e Educação e o Shopping Center poderão sofrer alterações no contexto da aprovação do Projeto Legal na Prefeitura Municipal de São Paulo, em virtude de determinação ou exigência dos poderes públicos, e/ou por critérios técnicos construtivos e mercadológicos, a critério exclusivo da Incorporadora. O Complexo de Inovação, Saúde e Educação, o Shopping Center e o empreendimento imobiliário Residencial serão empreendimentos distintos e independentes, sendo cada um objeto de aprovações legais na Prefeitura Municipal de São Paulo, bem como objeto de incorporações imobiliárias distintas. Área comum, privativa e paisagismo do empreendimento – As perspectivas aqui apresentadas são ilustradas com sugestões de decoração e paisagismo. Os acabamentos e/ou revestimentos serão entregues conforme o Memorial Descritivo do empreendimento. O empreendimento será entregue com vegetação implantada em forma de mudas, e as ilustrações artísticas representam a fase adulta das espécies constantes no projeto executivo de paisagismo. Plantas – A ilustração artística da planta do apartamento-tipo apresenta sugestão de decoração. As medidas são de face a face das paredes, de acordo com projeto da Prefeitura, sujeitas a alterações em decorrência da execução da obra e dos acabamentos a serem utilizados. Os layouts, mobiliário, cores e paginações de acabamentos apresentados nas imagens de venda dos apartamentos são ilustrativos. Os apartamentos serão entregues conforme Memorial Descritivo do empreendimento.*A área privativa do apartamento inclui a área do hall e do depósito privativo. Implantação do empreendimento Residencial – Perspectiva ilustrada da implantação, vista aérea e fachada do empreendimento residencial. Futura intermediação: BEM – Bem Vendas/Benx Incorporadora. Av. Dr. Cardoso de Melo, 1.460 – 9º andar – Vila Olímpia – CEP 04548-004 – São Paulo-SP – Creci: 20197J; F. MERA – Fernandez Mera Negócios Imobiliários. Av. Brigadeiro Luís Antônio, 4.910 – Jardim Paulista – CEP 01402-002 – São Paulo-SP – Creci: 22.061-J – Tel.: (11) 3066-1000 – www.fmera.com.br; ABYARA – Central de Atendimento da ABYARA BROKERS Intermediação Imobiliária. Av. Ibirapuera, 2.332 – Indianópolis – CEP 04028-002 –Tel.: 3888-9200 – São Paulo, diariamente até as 21 horas, inclusive sábados, domingos e feriados. Creci: 20.363-J; R Brokers/GHI Negócios Imobiliários – Creci: 25687-J. Rua Cunha Gago, 700 – conj. 91 – CEP 05421-001 – São Paulo-SP – Tel.: (11) 3467-1100 – www.ghiimobiliaria.com.br. Todas as imagens e perspectivas contidas neste material são meramente ilustrativas, podendo sofrer alterações, inclusive quanto a forma, cor, textura, posição e tamanho. As unidades autônomas e áreas comuns do empreendimento serão entregues conforme Projeto Legal, Memorial de Incorporação e Memorial Descritivo de Acabamento do empreendimento, que prevalecerão em caso de conflito com qualquer outro material ou informação relativa ao empreendimento.', 'Av. Major Sylvio de Magalhães Padilha, km 14', 'Av. Major Sylvio de Magalhães Padilha, km 14, Parque Global - São Paulo/SP', '05693-000', 'Marginal Pinheiros 14.500  - Real Parque -  São Paulo/SP', NULL, 'https://m.uber.com/go/home?drop%5B0%5D=%7B%22addressLine1%22%3A%22Parque%20Global%22%2C%22addressLine2%22%3A%22Marginal%20Pinheiros%2C%2014.500%20-%20Jardim%20Fonte%20do%20Morumbi%2C%20S%C3%A3o%20Paulo%20-%20SP%22%2C%22id%22%3A%22ChIJ___guydRzpQROFbJulTLsEQ%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.624718899999998%2C%22longitude%22%3A-46.712091199999996%2C%22provider%22%3A%22google_places%22%7D&amp;marketing_vistor_id=904298d5-f2e2-4b76-9498-fdd3b39d18d9&amp;uclick_id=234a1efd-c2e9-4f29-a9ae-b3dcb880a591', 'https://www.google.com/maps/place/Parque+Global/@-23.6247189,-46.7120912,17z/data=!3m1!4b1!4m6!3m5!1s0x94ce5127bbe0ffff:0x44b0cb54bac95638!8m2!3d-23.6247189!4d-46.7120912!16s%2Fg%2F11rtsjv377?hl=pt-PT&amp;entry=ttu&amp;g_ep=EgoyMDI2MDQyMC4wIKXMDSoASAFQAw%3D%3D', 'https://www.waze.com/pt-BR/live-map/directions/parque-global-marg.-pinheiros-14500-sao-paulo?to=place.w.205325852.2053192982.1995723', 'wp/2026/04/PARQUE-GLOBAL-│-TORRE-RESIDENCE-│-FACHADA-scaled.jpg', NULL, 'https://www.youtube.com/watch?v=PQo0E5YCx8w&amp;t=7s', 'wp/2026/04/Parque-Global-Tumb.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, false, true, true, false, '["Acesso direto ao Boulevard Parque Global.", "Bosque Privativo com 1.500 m² e Dog Park.", "Acesso exclusivo com porte-cochère ao lado do Bosque.", "Bicicletário com capacidade para 300 bikes, equipado com bikebox.", "Térreo elevado com lazer completo.", "Sky Lounge no 36º andar.", "Delivery com smart lockers, preparado para receber encomendas dos usuários com segurança.", "Certificação ambiental AQUA e de saúde e bem-estar FITWEL."]', '[{"nome": "Porte cochère / lobby principal"}, {"nome": "Lobby / lounge social"}, {"nome": "Bosque / jardim privativo / praça"}, {"nome": "Piscina semiolímpica com borda infinita"}, {"nome": "Piscina infantil"}, {"nome": "Sky lounge / rooftop wellness"}, {"nome": "Spa / sauna / hidromassagem / ice pool"}, {"nome": "Academia / fitness"}, {"nome": "Salão de festas / gourmet interno"}, {"nome": "Gourmet externo / churrasqueira com forno de pizza"}, {"nome": "Coworking"}, {"nome": "Brinquedoteca / playground"}, {"nome": "Quadra de beach tennis"}, {"nome": "Pet place / dog park"}, {"nome": "Delivery / lockers / concierge"}, {"nome": "Bicicletário / oficina"}, {"nome": "Market / minimarket"}, {"nome": "Área comum 1", "imagem": "wp/2026/04/PARQUE-GLOBAL-│-TORRE-RESIDENCE-│-ACADEMIA.jpg"}, {"nome": "Área comum 2", "imagem": "wp/2026/04/PARQUE-GLOBAL-│-TORRE-RESIDENCE-│-BEACH-TENNIS.jpg"}, {"nome": "Área comum 3", "imagem": "wp/2026/04/PARQUE-GLOBAL-│-TORRE-RESIDENCE-│-BICICLETARIO.jpg"}, {"nome": "Área comum 4", "imagem": "wp/2026/04/PARQUE-GLOBAL-│-TORRE-RESIDENCE-│-BRINQUEDOTECA.jpg"}, {"nome": "Área comum 5", "imagem": "wp/2026/04/PARQUE-GLOBAL-│-TORRE-RESIDENCE-│-COWORKING.jpg"}, {"nome": "Área comum 6", "imagem": "wp/2026/04/PA