INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('4d21f562-f391-46cc-8299-cfe49907dc7c', 'olimpiadas', 'Olimpíadas', 'Edifício corporativo na Rua Olimpíadas, 134, na Vila Olímpia, com lajes corporativas, infraestrutura para ar-condicionado VRF, piso elevado e elevadores com antecipação de chamadas.', NULL, 'pronto_para_morar', NULL, 'Edifício projetado pelo escritório Botti Rubin Arquitetos, integrado aos edifícios Capital Center e One Hundred, formando um conjunto arquitetônico visualmente integrado na Vila Olímpia, com foco em tecnologia e sustentabilidade.
INSERT INTO public.empreendimentos (id, slug, nome, subtitulo, tipo_habitacao, status_obra, previsao_entrega, o_projeto, arquitetura, paisagismo, interiores, total_unidades, total_andares, unidades_por_andar, numero_torres, area_terreno, area_construida_total, metragem_residencial, metragem_nr, quartos, vagas, texto_legal, endereco_parcial, endereco_completo, cep, endereco_vendas, stand_de_vendas, link_uber, link_maps, link_waze, imagem_principal, logotipo, url_video_principal, thumbnail_video, url_tour_virtual, vistas_do_andar, obra_fundacao, obra_alvenaria, obra_acabamento, obra_total, obra_atualizada_em, visivel, exibir_obras, exibir_plantas, exibir_localizacao, modo_breve_lancamento, diferenciais, areas_comuns, certificacoes, detalhes_localizacao, tags_card, cidade_id, bairro_id, categoria_id, linha_produto_id, criado_em, atualizado_em, obra_documentacao, redirecionar_para, relacionados, seo_titulo, seo_descricao) VALUES ('e4c8e024-a002-4406-bc1a-ccf6d1690151', 'artsy-itaim', 'Artsy Itaim', 'ARTE QUE SE MANIFESTA ATRAVÉS DOS ESPAÇOS.', NULL, 'pronto_para_morar', NULL, 'Dando continuidade ao sonho de um dos mais importantes arquitetos paisagistas da história do país, reconhecido internacionalmente, o Escritório Burle Marx, responsável por sua obra, concretiza no Artsy Itaim, o Art Wall, criando no empreendimento um toque máximo de exclusividade.', 'Burle Marx', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '181m²', NULL, '3 Suítes', '3 vagas', 'Em conformidade com a Lei Geral de Proteção de Dados, informamos que seus dados pessoais serão solicitados com a finalidade de acompanhar seu histórico de interações, manter você informado sobre nossos lançamentos e promoções, realizar pesquisas de opinião e satisfação e compartilhar seus dados com a imobiliária e o corretor parceiro, que irá te atender quando for autorizado. Seus dados serão mantidos em rigorosa política segurança e a qualquer momento, você poderá solicitar que seus dados pessoais sejam excluídos de nossos sistemas. A Benx Incorporadora não possui não possui qualquer parceria com outras empresas, sejam de móveis planejados, compra e venda de imóveis, veículos e afins. Os únicos produtos fornecidos por nós são os veiculados neste site e nas redes sociais descritas em seu rodapé. Caso receba algum contato/oferta com informação divergente da descrita acima, trata-se de fato inverídico e fraudulento. Caso passem por essa situação, por favor, entrem em contato conosco através do e-mail: relacionamento@benx.com.br.', 'Rua Ferreira Lobo, 361', 'Rua Ferreira Lobo, 361 - Itaim, São Paulo/SP', NULL, NULL, NULL, 'https://m.uber.com/go/pickup?drop%5B0%5D=%7B%22addressLine1%22%3A%22R.%20Cel.%20Joaquim%20Ferreira%20Lobo%20-%20Vila%20Nova%20Concei%C3%A7%C3%A3o%22%2C%22addressLine2%22%3A%22S%C3%A3o%20Paulo%20-%20SP%22%2C%22id%22%3A%22ChIJSZHhfUVXzpQRgnNx0siwWZ8%22%2C%22source%22%3A%22SEARCH%22%2C%22latitude%22%3A-23.593120799999998%2C%22longitude%22%3A-46.6812483%2C%22provider%22%3A%22google_places%22%7D&amp;marketing_vistor_id=904298d5-f2e2-4b76-9498-fdd3b39d18d9&amp;uclick_id=67256e22-08e8-4fa6-afbc-a0e85001b10a', 'https://www.google.com/maps/place/R.+Cel.+Joaquim+Ferreira+Lobo,+361+-+Vila+Ol%C3%ADmpia,+S%C3%A3o+Paulo+-+SP,+04544-150/@-23.5936053,-46.6856875,17z/data=!3m1!4b1!4m6!3m5!1s0x94ce57458789718f:0xa95e2a4a65717f77!8m2!3d-23.5936053!4d-46.6831126!16s%2Fg%2F11csfn1ymb!5m2!1e4!1e2?entry=ttu&amp;g_ep=EgoyMDI2MDUyMC4wIKXMDSoASAFQAw%3D%3D', 'https://www.waze.com/pt-BR/live-map/directions/br/sp/r.-cel.-joaquim-ferreira-lobo,-361?to=place.ChIJj3GJh0VXzpQRd39xZUoqXqk', 'wp/2026/05/ARTSY-ITAIM-│-COBERTURA.jpg', NULL, 'https://www.youtube.com/watch?v=VWG6KGivILM', 'wp/2026/05/Captura-de-tela-2026-05-26-170840.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, false, true, true, false, '[]', '[{"nome": "Área comum 1", "imagem": "wp/2026/05/ARTSY-ITAIM-│-ACADEMIA.jpg"}, {"nome": "Área comum 2", "imagem": "wp/2026/05/ARTSY-ITAIM-│-BRINQUEDOTECA.jpg"}, {"nome": "Área comum 3", "im