INSERT INTO public.posts_jornal (id, slug, titulo, categoria, fonte, fonte_url, resumo, conteudo, imagem, data_publicacao, destaque, publicado, criado_em, atualizado_em, seo_titulo, seo_descricao) VALUES ('585c6e67-743d-4d6b-a3bc-04b17cfa67b2', 'com-predio-como-escultura-benx-ve-potencial-para-apartamento-de-ate-r-180-mi', 'Com prédio como ‘escultura’, Benx vê potencial para apartamento de até R$ 180 mi', 'Sem categoria', 'Bloomberg Linea', 'https://www.bloomberglinea.com.br/negocios/com-predio-em-formato-de-escultura-benx-reforca-estrategia-no-mercado-de-luxo/', 'Incorporadora aposta em fortalecimento da marca no mercado de luxo com empreendimento que descreve como icônico na região da Faria Lima, que pode se tornar o mais caro de São Paulo, conta o CEO Luciano Amaral à Bloomberg Línea', 'A Benx prepara o lançamento do 280 Art Boulevard, um edifício concebido como escultura no coração do Itaim Bibi. Erguido sobre um raro terreno triangular, o prédio — com fachada curva que lembra a letra “J” — busca não apenas ocupar um vazio urbano, mas criar um marco visual na fronteira entre a Faria Lima e a Cidade Jardim. Serão apenas 22 apartamentos de grandes metragens, além de gardens e uma cobertura duplex, todos diferentes entre si graças às curvas da torre.
INSERT INTO public.posts_jornal (id, slug, titulo, categoria, fonte, fonte_url, resumo, conteudo, imagem, data_publicacao, destaque, publicado, criado_em, atualizado_em, seo_titulo, seo_descricao) VALUES ('d6569bea-b046-4f0e-ad5c-0fbb078e3732', 'falta-mao-de-obra-na-construcao-civil-institutos-oferecem-capacitacao-de-graca', 'Falta mão de obra na construção civil - Institutos oferecem capacitação de graça', 'Sem categoria', 'Bom Dia SP', 'https://globoplay.globo.com/v/13761711/?s=0s', NULL, 'Reportagem do Bom Dia SP apresenta o Instituto Bueno Netto como uma das forças que tentam preencher, gratuitamente, o buraco de qualificação que freia a construção civil em São Paulo. Num estado com 1,6 milhão de trabalhadores no setor e déficit de mais de 30 mil vagas só na capital, a câmera mostra que, entre tantos prédios em obra, faltam justamente profissionais preparados.
INSERT INTO public.posts_jornal (id, slug, titulo, categoria, fonte, fonte_url, resumo, conteudo, imagem, data_publicacao, destaque, publicado, criado_em, atualizado_em, seo_titulo, seo_descricao) VALUES ('be3181f1-ee84-4a2d-bcf2-9ef1419aa850', 'instituto-bueno-netto-e-fundo-social-oferecem-cursos-gratuitos-para-formar-profissionais-para-a-construcao-civil', 'Instituto Bueno Netto e Fundo Social oferecem cursos gratuitos para formar profissionais para a construção civil', 'Sem categoria', 'G1', 'https://g1.globo.com/sp/sao-paulo/noticia/2025/06/16/em-parceria-com-o-senac-instituto-bueno-netto-oferece-cursos-gratuitos-na-construcao-civil.ghtml', 'Qualificação atrai desde jovens até mulheres e pessoas em busca de uma nova carreira no setor em expansão.', 'Reportagem do G1 mostra o Instituto Bueno Netto, em parceria com o Senai, e o Fundo Social de São Paulo oferecendo cursos gratuitos para suprir a falta de mão de obra qualificada na construção civil. As formações incluem alvenaria, elétrica, carpintaria e assentamento de pisos, entre outras, com vale-transporte, alimentação e lanche; basta ter ensino fundamental completo, mais de 18 anos e vontade de aprender, sem exigência de experiência prévia.
INSERT INTO public.posts_jornal (id, slug, titulo, categoria, fonte, fonte_url, resumo, conteudo, imagem, data_publicacao, destaque, publicado, criado_em, atualizado_em, seo_titulo, seo_descricao) VALUES ('f0da325d-a0ee-476b-9f44-fad2c0450f5a', 'fotografo-joao-farkas-e-destaque-da-temporada-brasil-na-franca', 'Fotógrafo João Farkas é destaque da temporada Brasil na França', 'Sem categoria', 'Bravo!', 'https://bravo.abril.com.br/arte/fotografo-joao-farkas-e-destaque-da-temporada-brasil-na-franca/', 'O artista exibe série sobre o litoral norte do Brasil em mostra ao ar livre em Paris', 'A Bravo! apresenta João Farkas como um dos destaques do Ano do Brasil na França, com uma exposição ao ar livre às margens do Sena que evita clichês turísticos e aposta em imagens mais enigmáticas. Com curadoria de Emílio Kalil, a mostra reúne 18 fotos, muitas da série Costa Norte, fruto de sete expedições por 2.200 km de litoral entre Amapá e Rio Grande do Norte, marcada pela ocupação acelerada do território.
INSERT INTO public.posts_jornal (id, slug, titulo, categoria, fonte, fonte_url, resumo, conteudo, imagem, data_publicacao, destaque, publicado, criado_em, atualizado_em, seo_titulo, seo_descricao) VALUES ('431368c7-d90e-4969-b507-1f83b7b67cbd', 'esquisitices-de-rico-a-forca-do-quadril-e-aquele-barulhinho-bom-tem-muito-de-tudo', 'Esquisitices de rico, a força do quadril e aquele barulhinho bom: tem muito de tudo!', 'Sem categoria', 'Caixa Postal - Joyce Pascowitch', 'https://caixapostal.news/posts/esquisitices-de-rico-a-forca-do-quadril-e-aquele-barulhinho-bom-tem-muito-de-tudo', NULL, 'Soube que o eixo da avenida Cidade Jardim — que liga MIS, MuBE e Casa Museu Ema Klabin — ganha um novo marco urbano: uma obra de Giácomo Tomazzi, que vai fazer parte do 280 Art Boulevard — moradias super exclusivas, ainda em construção, lançadas por Luciano Amaral e Adalberto Bueno Netto.', 'jornal/2025/12/Picture3.png', '2025-12-18 18:55:12', false, true, '2026-06-04 13:32:20.881771', '2026-06-04 13:32:20.877', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.posts_jornal (id, slug, titulo, categoria, fonte, fonte_url, resumo, conteudo, imagem, data_publicacao, destaque, publicado, criado_em, atualizado_em, seo_titulo, seo_descricao) VALUES ('4295a363-8569-4b2f-b231-1b087324d294', 'com-real-enfraquecido-brasil-atrai-turistas-de-saude', 'Com real enfraquecido, Brasil atrai "turistas de saúde"', 'Sem categoria', 'Deutsche Welle', 'https://www.dw.com/pt-br/com-real-enfraquecido-brasil-atrai-turistas-de-sa%C3%BAde-do-exterior/a-73567391', NULL, 'O turismo médico no Brasil cresce entre 15% e 25% ao ano, impulsionado pela desvalorização do real, pela reputação da medicina privada brasileira e pela estrutura hospitalar robusta de cidades como São Paulo. Reportagem reúne relatos de estrangeiros — da suíça Nicole Schultheiss à americana Adrianna Rains — que viajam ao país para cirurgias estéticas planejadas em videoconferência e concluídas com acompanhamento remoto.
INSERT INTO public.posts_jornal (id, slug, titulo, categoria, fonte, fonte_url, resumo, conteudo, imagem, data_publicacao, destaque, publicado, criado_em, atualizado_em, seo_titulo, seo_descricao) VALUES ('1ecd5107-d57b-4b63-837b-53824834ff65', 'grupo-emiliano-poe-a-venda-quartos-de-hoteis-de-luxo-para-investidores-veja-como-funciona', 'Grupo Emiliano põe à venda quartos de hotéis de luxo para investidores; veja como funciona', 'Sem categoria', 'O Estado de S. Paulo', 'https://www.estadao.com.br/viagem/emiliano-venda-quartos-hoteis-luxo-investimento/', 'Venda de unidades tornou-se um negócio lucrativo para incorporadoras e retorno do investimento pode aparecer em poucos anos', 'O mercado hoteleiro brasileiro vive uma inversão de lógica: em vez de pagar diárias, investidores passam a comprá-las como ativo. Reportagem mostra a expansão da v3rso, bandeira do Hotel Emiliano voltada a operações mais enxutas e rentáveis, que vende quartos — a partir de R$ 1 milhão — como unidades imobiliárias capazes de gerar retorno. A estratégia inclui parcerias regionais e um plano de chegar a 100 hotéis em 15 anos, com estreias em Porto Alegre, Goiânia e São Paulo.
INSERT INTO public.posts_jornal (id, slug, titulo, categoria, fonte, fonte_url, resumo, conteudo, imagem, data_publicacao, destaque, publicado, criado_em, atualizado_em, seo_titulo, seo_descricao) VALUES ('b62c49e2-9c11-4e76-88cd-8a91791d571d', 'so-a-maquete-de-um-empreendimento-de-luxo-vale-o-preco-de-um-apartamento', 'Só a maquete de um empreendimento de luxo vale o preço de um apartamento', 'Sem categoria', 'O Estado de S. Paulo', 'https://digital.estadao.com.br/article/281487872296966', 'Representação do Parque Global, em SP, com torres residenciais, hospital, hotel, shopping center e parque. Gasto com uma miniatura pode ir a R$ 2 milhões.', 'O Estadão mostra como maquetes gigantes e caríssimas viraram arma de sedução no mercado de superluxo, onde empreendimentos com VGV bilionário disputam um comprador que pode escolher entre Camboriú, São Paulo ou Miami. No caso da Senna Tower, em Balneário Camboriú, a FG ergueu uma maquete de 16 metros, com LEDs e estrutura metálica, que pode custar até R$ 2 milhões e integra um estande de vendas de R$ 30 milhões — tudo pensado para transformar o futuro prédio mais alto do mundo em atração turística antes mesmo da obra.
INSERT INTO public.posts_jornal (id, slug, titulo, categoria, fonte, fonte_url, resumo, conteudo, imagem, data_publicacao, destaque, publicado, criado_em, atualizado_em, seo_titulo, seo_descricao) VALUES ('e0ffb643-8732-4500-a9b3-ae8d89dea6ed', 'grupo-bueno-netto-prepara-shopping-de-r-15-bi-na-marginal-pinheiros', 'Grupo Bueno Netto prepara shopping de R$ 1,5 bi na Marginal Pinheiros', 'Sem categoria', 'O Estado de S. Paulo', 'https://www.estadao.com.br/economia/coluna-do-broad/grupo-bueno-netto-prepara-shopping-de-r-15-bi-na-marginal-pinheiros/', 'Empreendimento será construído no Parque Global e deve ter a Allos como parceira', 'O Estadão revela que o Grupo Bueno Netto vai finalmente lançar o shopping center do Parque Global, após anos de entraves ambientais. O projeto — investimento de R$ 1,5 bilhão — deve ter as obras iniciadas ainda este ano, assim que sair o alvará final. A Allos, maior player do setor, negocia entrar como sócia estratégica ou administradora, dependendo das condições regulatórias e de mercado.
INSERT INTO public.posts_jornal (id, slug, titulo, categoria, fonte, fonte_url, resumo, conteudo, imagem, data_publicacao, destaque, publicado, criado_em, atualizado_em, seo_titulo, seo_descricao) VALUES ('5288eb77-b0b6-4276-8f3f-c94be3af4430', 'benx-aposta-em-grife-propria-de-imoveis-de-luxo-pininfarina-tem-no-brasil-todo-diz-presidente', 'Benx aposta em grife própria de imóveis de luxo; ''Pininfarina tem no Brasil todo'', diz presidente', 'Sem categoria', 'O Estado de S. Paulo', 'https://www.estadao.com.br/economia/geracao-prateada-trabalhadores-60-crescimento-mercado-de-trabalho/', 'Incorporadora lança a marca Arbórea para cinco projetos estimados em R$ 3 bilhões', 'O Broadcast mostra que a Benx decidiu nadar contra a tendência dos branded residences globais e criar sua própria marca de luxo: a linha Arbórea, focada no “altíssimo, altíssimo padrão”. Em vez de associar seus prédios a grifes como Pininfarina, a empresa aposta em arquitetura autoral, paisagismo de referência, acervo permanente de arte e unidades acima de 400 m² — com preços que começam em cerca de R$ 25 milhões. O primeiro Arbórea, no Itaim, valorizou após a entrega, com unidades anunciadas a R$ 30 milhões e cobertura a R$ 140 milhões, impulsionando a expansão para Jardim Europa, Jardins, Ibirapuera e Chácara Santo Antônio.
